import os, json, csv
from datetime import datetime
csv_path = 'exp8_csv_small/csv/urban_air_quality_sensors_1_1.csv'
print("Evidence from urban_air_quality_sensors_1_1.csv (hyper_param_index=1, total_hyper_params=1):")

with open(csv_path, newline='') as f:
  reader = csv.DictReader(f)
  rows = list(reader)
  headers = reader.fieldnames or []
total_rows = len(rows)

# detect sensor column
sensor_col = None
for h in headers:
  lh = h.lower()
  if 'sensor' in lh and 'id' in lh:
    sensor_col = h; break
if sensor_col is None:
  for h in headers:
    lh = h.lower()
    if lh in ('sensor','sensor_id','id','device_id','station'):
      sensor_col = h; break

unique_sensors = 0
if sensor_col:
  vals = [r.get(sensor_col) for r in rows if r.get(sensor_col) not in (None,'')]
  unique_sensors = len(set(vals))

print("Total rows:", total_rows)
print("Unique sensors:", unique_sensors)

# Load JSON parameter files in the same directory
base_dir = os.path.dirname(csv_path)
params_all = {}
payload_all = {}
for fname in os.listdir(base_dir):
  if not fname.lower().endswith('.json'): continue
  try:
    with open(os.path.join(base_dir, fname), 'r') as jf:
      data = json.load(jf)
  except Exception:
    continue
  lname = fname.lower()
  if 'payload' in lname:
    if isinstance(data, dict): payload_all.update(data)
  else:
    if isinstance(data, dict): params_all.update(data)

# Diurnal-related params
diurnal_keys = [k for k in params_all.keys() if 'diurnal' in k.lower()]
if diurnal_keys:
  print("Diurnal-related hyper-parameters from params_json:")
  for k in diurnal_keys:
    print(f"  {k}: {params_all[k]}")

# Anomaly-related params
anom_keys = [k for k in params_all.keys() if 'anomal' in k.lower()]
if anom_keys:
  print("Anomaly-related hyper-parameters from params_json:")
  for k in anom_keys:
    print(f"  {k}: {params_all[k]}")

# Attempt to infer diurnal pattern from timing data, if possible
pm_col = None
for c in headers:
  lc = c.lower()
  if lc in ('pm25','pm2.5','pm2_5','pm'):
    pm_col = c
    break
if not pm_col:
  for c in headers:
    if 'pm' in c.lower():
      pm_col = c; break

time_col = None
for c in headers:
  lc = c.lower()
  if lc in ('timestamp','time','datetime','time_stamp'):
    time_col = c; break

diurnal_insight = ""
if time_col and pm_col:
  hour_sum = {}
  count = {}
  for r in rows:
    tval = r.get(time_col,'')
    pval = r.get(pm_col)
    if pval in (None,''): continue
    try:
      p = float(pval)
    except:
      continue
    hour = None
    if isinstance(tval, str) and tval:
      for fmt in ("%Y-%m-%d %H:%M:%S","%Y-%m-%dT%H:%M:%S","%Y/%m/%d %H:%M:%S"):
        try:
          dt = datetime.strptime(tval, fmt)
          hour = dt.hour
          break
        except:
          pass
    if hour is None:
      continue
    hour_sum[hour] = hour_sum.get(hour, 0.0) + p
    count[hour] = count.get(hour, 0) + 1
  if hour_sum:
    means = {h: hour_sum[h]/count[h] for h in hour_sum}
    hmax = max(means, key=means.get)
    hmin = min(means, key=means.get)
    amp = means[hmax] - means[hmin]
    diurnal_insight = f"Mean PM2.5 is highest around hour {hmax} and lowest around hour {hmin}, with approximate diurnal amplitude {amp:.2f} units."
print("Diurnal data-driven insight:", diurnal_insight or "Insufficient data to infer diurnal pattern from CSV timing information.")

# Simple anomaly count based on distribution
if pm_col:
  vals = []
  for r in rows:
    v = r.get(pm_col)
    if v not in (None,''):
      try:
        vals.append(float(v))
      except:
        pass
  if vals:
    vals.sort()
    import statistics
    med = statistics.median(vals)
    stdev = statistics.pstdev(vals)
    anom_count = sum(1 for v in vals if v > med + 2*stdev)
    print("Anomaly-like events detected (relative to distribution):", anom_count)
# Show a hint of payload_json keys if present
if payload_all:
  print("payload_json keys observed:", ", ".join(sorted(payload_all.keys())))
else:
  print("Note: No payload_json keys found in this directory.")
