import csv, math, json
path='exp8_csv_small/csv/telecom_spectrum_management_1_1.csv'
with open(path) as f:
    r=csv.DictReader(f)
    rows=list(r)
n=len(rows)
cols=r.fieldnames
# detect columns
ch_col = next((c for c in cols if 'channel' in c.lower() and 'usage' in c.lower()), None)
payload_col = next((c for c in cols if 'payload' in c.lower() and 'json' in c.lower()), None)
anom_col = next((c for c in cols if 'anomaly' in c.lower() or 'anomaly_score' in c.lower()), None)
uplift_col = next((c for c in cols if 'uplift' in c.lower()), None)
time_col = next((c for c in cols if c.lower() in ('time','t','row','row_index','position','timestamp')), None)

base=50.0; amp=0.4*base; period=24.0

def t_from(i, rw):
    if time_col:
        v=rw.get(time_col)
        try: return float(v)
        except: return i
    return i

def baseline(i, rw):
    t=t_from(i, rw)
    return base + amp*math.sin(2*math.pi*t/period)

anom_indices=[]
if anom_col:
    for i, rw in enumerate(rows):
        v=rw.get(anom_col)
        try:
            if int(v)==1: anom_indices.append(i)
        except:
            pass

def actual(i):
    if ch_col:
        v=rows[i].get(ch_col)
        if v is None or v=='':
            return None
        try: return float(v)
        except: return None
    return None

def t_int(i):
    return int(t_from(i, rows[i]))

print("rows:", n)
print("columns:", cols)
print("channel_usage_col:", ch_col)
print("payload_col:", payload_col)
print("anomaly_col:", anom_col)
print("uplift_col:", uplift_col)
print("seasonal: base=", base, "amplitude=", amp, "period=", period)

# seasonal baseline min/max
mn=1e9; mx=-1e9
for i in range(n):
    b=baseline(i, rows[i])
    if b<mn: mn=b
    if b>mx: mx=b
print("seasonal_baseline_min=", round(mn,2), "max=", round(mx,2))

print("anomaly_count:", len(anom_indices))
print("sample rows:")
for i in range(min(4,n)):
    print(i, "t=", t_int(i), "baseline=", round(baseline(i, rows[i]),2), "actual=", actual(i))

print("anomaly_payload_samples (first 3):")
for i in anom_indices[:3]:
    if payload_col:
        p=rows[i].get(payload_col)
        if p:
            try:
                obj=json.loads(p)
                print("row", i, "payload_keys_sample:", list(obj.keys())[:5])
            except:
                print("row", i, "payload_unparsed")
