import csv, json

path = 'exp8_csv_small/csv/autonomous_vehicle_scenarios_1_1.csv'
with open(path, newline='', encoding='utf-8') as f:
    rows = list(csv.DictReader(f))

params_col = None
payload_col = None
if rows:
    for c in rows[0].keys():
        lc = c.lower()
        if 'params' in lc and 'json' in lc:
            if not params_col: params_col = c
        if 'payload' in lc and 'json' in lc:
            if not payload_col: payload_col = c
    if 'params_json' in rows[0]:
        params_col = 'params_json'
    if 'payload_json' in rows[0]:
        payload_col = 'payload_json'

def jload(s):
    try: return json.loads(s)
    except: return None

def flatten(d, p=''):
    out = {}
    if isinstance(d, dict):
        for k, v in d.items():
            nk = f'{p}.{k}' if p else k
            if isinstance(v, dict):
                out.update(flatten(v, nk))
            else:
                out[nk] = v
    else:
        out[p] = d
    return out

# Parse
parses = []
for r in rows:
    if params_col and r.get(params_col):
        parses.append(jload(r[params_col]))
    else:
        parses.append(None)

# Build per-row payloads and flatten
payloads = []
for r in rows:
    payloads.append(jload(r[payload_col]) if payload_col and r.get(payload_col) else None)

# Summary
print('Rows:', len(rows))
print('Params column:', params_col or 'NOT_FOUND')
print('Payload column:', payload_col or 'NOT_FOUND')

# Unique configurations
config_keys = []
for p in parses:
    if p is None:
        config_keys.append(None)
    else:
        try:
            config_keys.append(tuple(sorted(p.items())))
        except TypeError:
            config_keys.append(json.dumps(p, sort_keys=True))

groups = {}
for i, k in enumerate(config_keys):
    groups.setdefault(k, []).append(i)
print('Unique hyper-parameter configurations across rows:', len(groups))

# Show per-row insights
for i, r in enumerate(rows):
    print('Row', i, 'params_json present?', bool(parses[i]))
    if parses[i] is not None:
        print('  params_json keys:', sorted(parses[i].keys()))
        print('  representative params_json snippet:', {k: parses[i][k] for k in list(parses[i].keys())[:3]})

    if payload_col and r.get(payload_col):
        pl = payloads[i]
        if isinstance(pl, dict):
            pl_keys = sorted(flatten(pl).keys())[:8]
            print('  payload_json top-flattened keys (sample):', pl_keys)

print('Attempting simple param-to-payload alignment (shared top-level keys):')
for i, p in enumerate(parses):
    if p is None: continue
    if payloads[i] and isinstance(payloads[i], dict):
        pf = flatten(payloads[i])
        pflat = p if isinstance(p, dict) else {}
        common = sorted(set(pflat).intersection(set(pf)))
        for key in common:
            pv = pflat[key]
            pv2 = pf[key]
            if not isinstance(pv, (dict, list)) and not isinstance(pv2, (dict, list)):
                print('Row', i, 'param.' + key, '=', pv, '-> payload.' + key, '=', pv2)

print('\nHyper-parameter indexing interpretation:')
print(' - This run claims total_hyper_params=1 and hyper_param_index=1.')
print(' - If there is only one unique configuration across all rows, then every row reflects the same settings in params_json, and the generated payloads are produced from that same configuration.')
print(' - Changing hyper_param_index would only change the CSV if there were multiple distinct hyper-parameter configurations present (i.e., groups > 1). In this file, the count above indicates how many distinct configs exist; if that count is 1, hyper_param_index has no effect on the CSV output.')
